// src/context/AuthContext.jsx
import { createContext, useContext, useState, useEffect } from "react";

const AuthContext = createContext();

// 권한 등급 정의 (숫자가 높을수록 상위 권한)
export const ROLES = {
  STAFF: "staff",       // 직원
  MANAGER: "manager",   // 매장관리자
  OWNER: "owner",       // 대표자
};

// 등급별 접근 가능한 메뉴/기능 목록
export const ROLE_PERMISSIONS = {
  staff: [
    "pos",           // POS 판매
    "products.view", // 상품 조회
    "receipt",       // 영수증
    "schedule.own",  // 본인 스케줄
    "kakaopay",      // 카카오페이 결제
  ],
  manager: [
    "pos",
    "products.view",
    "products.edit",  // 상품 등록/수정
    "inventory",      // 재고 관리
    "sales.daily",    // 일별 매출 조회
    "discount",       // 할인/쿠폰 설정
    "order",          // 발주 관리
    "receipt",
    "schedule.own",
    "kakaopay",
  ],
  owner: [
    "pos",
    "products.view",
    "products.edit",
    "inventory",
    "sales.daily",
    "sales.all",      // 전체 매출 통계
    "discount",
    "order",
    "receipt",
    "schedule.own",
    "schedule.all",   // 전체 스케줄
    "kakaopay",
    "users.manage",   // 직원 계정 관리
    "roles.manage",   // 권한 등급 설정
    "settings",       // 시스템 설정
    "payroll",        // 급여/정산
  ],
};

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);

  useEffect(() => {
    // 로컬스토리지에서 로그인 상태 복원
    const stored = localStorage.getItem("srmart_user");
    if (stored) {
      setUser(JSON.parse(stored));
    }
  }, []);

  const login = (userData) => {
    // userData 예시: { id: 1, name: "홍길동", email: "...", role: "owner" }
    setUser(userData);
    localStorage.setItem("srmart_user", JSON.stringify(userData));
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem("srmart_user");
  };

  // 특정 기능에 접근 가능한지 확인하는 함수
  const hasPermission = (permission) => {
    if (!user) return false;
    const perms = ROLE_PERMISSIONS[user.role] || [];
    return perms.includes(permission);
  };

  // 특정 등급 이상인지 확인
  const hasRole = (requiredRole) => {
    if (!user) return false;
    const hierarchy = [ROLES.STAFF, ROLES.MANAGER, ROLES.OWNER];
    const userLevel = hierarchy.indexOf(user.role);
    const requiredLevel = hierarchy.indexOf(requiredRole);
    return userLevel >= requiredLevel;
  };

  return (
    <AuthContext.Provider value={{ user, login, logout, hasPermission, hasRole }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  return useContext(AuthContext);
}
